/**
 * 이름 마스킹 (중간 글자를 *로 대체)
 * "김철수" → "김*수", "홍길동" → "홍*동"
 */
export function maskName(name: string): string {
  if (!name) return "";
  if (name.length <= 1) return name;
  if (name.length === 2) return name[0] + "*";
  return name[0] + "*".repeat(name.length - 2) + name[name.length - 1];
}

/**
 * 작성자명 표시 처리
 * - "@닉네임" 형태: 닉네임 그대로 노출 (블러 없음)
 * - 일반 이름: 마스킹 처리
 */
export function formatAuthorName(authorName: string): string {
  if (!authorName) return "";
  if (authorName.startsWith("@")) {
    return authorName.slice(1);
  }
  return maskName(authorName);
}

/**
 * 저장용 작성자명 생성
 * - 닉네임이 있으면 "@닉네임" 형태로 반환
 * - 없으면 이름 그대로 반환
 */
export function buildAuthorName(name: string, nickname?: string): string {
  if (nickname) return `@${nickname}`;
  return name || "익명";
}

/**
 * 한국어 날짜 포맷 (YYYY. MM. DD.)
 * null이면 fallback 문자열 반환
 */
export function formatDate(dateStr: string | null, fallback = "-"): string {
  if (!dateStr) return fallback;
  return new Date(dateStr).toLocaleDateString("ko-KR", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
}

/**
 * 한국어 날짜 포맷 (YYYY년 M월 D일)
 * CoursesTab 등에서 사용하는 긴 포맷
 */
export function formatDateLong(dateStr: string | null, fallback = ""): string {
  if (!dateStr) return fallback;
  return new Date(dateStr).toLocaleDateString("ko-KR", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

/**
 * 가격 포맷 (1000 → "1,000")
 */
export function formatPrice(price: number): string {
  return price.toLocaleString("ko-KR");
}

/**
 * 가격 문자열 파싱 ("1,000" → 1000)
 */
export function parsePrice(value: string): number {
  const numericValue = value.replace(/[^0-9]/g, "");
  return numericValue ? parseInt(numericValue, 10) : 0;
}

/**
 * Notion slug → Page ID 변환
 * 하이픈이 포함된 UUID는 그대로, 없으면 삽입
 */
export function slugToPageId(slug: string): string {
  if (slug.includes("-")) return slug;
  return [
    slug.slice(0, 8),
    slug.slice(8, 12),
    slug.slice(12, 16),
    slug.slice(16, 20),
    slug.slice(20),
  ].join("-");
}

/**
 * Notion Page ID UUID 형식 검증
 * 하이픈 있는/없는 UUID 모두 허용
 */
const UUID_REGEX = /^[0-9a-f]{8}-?[0-9a-f]{4}-?[0-9a-f]{4}-?[0-9a-f]{4}-?[0-9a-f]{12}$/i;

export function isValidNotionId(id: string): boolean {
  return UUID_REGEX.test(id);
}

/**
 * Rate Limiter: IP 또는 키 기반 요청 제한.
 * Redis(Upstash) 사용 가능 시 INCR+EXPIRE 기반 sliding window.
 * Redis 불가 시 globalThis Map fallback (로컬 개발용).
 * windowMs 동안 maxRequests 초과 시 true 반환.
 */
export function createRateLimiter(maxRequests: number, windowMs: number) {
  // fallback in-memory store
  const g = globalThis as typeof globalThis & { __rateLimiters?: Map<string, Map<string, number[]>> };
  if (!g.__rateLimiters) g.__rateLimiters = new Map();

  const storeKey = `${maxRequests}:${windowMs}`;
  if (!g.__rateLimiters.has(storeKey)) g.__rateLimiters.set(storeKey, new Map());
  const memStore = g.__rateLimiters.get(storeKey)!;

  return async function isRateLimited(limiterKey: string): Promise<boolean> {
    // Lazy import to avoid top-level side effects
    const { redis } = await import("@/lib/redis");

    if (redis) {
      const windowSec = Math.ceil(windowMs / 1000);
      const bucket = Math.floor(Date.now() / windowMs);
      const key = `rl:${storeKey}:${limiterKey}:${bucket}`;
      const count = await redis.incr(key);
      if (count === 1) await redis.expire(key, windowSec);
      return count > maxRequests;
    }

    // fallback: in-memory
    const now = Date.now();
    const timestamps = memStore.get(limiterKey) ?? [];
    const recent = timestamps.filter((t) => now - t < windowMs);
    memStore.set(limiterKey, recent);
    if (recent.length >= maxRequests) return true;
    recent.push(now);
    memStore.set(limiterKey, recent);
    return false;
  };
}

/**
 * Request에서 클라이언트 IP 추출
 */
export function getClientIp(request: { headers: { get(name: string): string | null } }): string {
  const forwarded = request.headers.get("x-forwarded-for");
  if (forwarded) return forwarded.split(",")[0].trim();
  return request.headers.get("x-real-ip") ?? "unknown";
}

/**
 * CSRF 방지: Origin 헤더 검증
 * 비인증 POST 요청에서 사용
 */
export function isValidOrigin(request: { headers: { get(name: string): string | null } }): boolean {
  const origin = request.headers.get("origin");
  const host = request.headers.get("host");
  if (!origin || !host) return false;
  try {
    const originHost = new URL(origin).host;
    return originHost === host;
  } catch {
    return false;
  }
}
