import Link from "next/link";
import CourseCard from "@/components/CourseCard";
import { ClockIcon } from "@/components/icons";
interface Course {
  id: string;
  title: string;
  description: string;
  price: number;
  duration: string;
  level: string;
  category: string;
  status: string;
  slug: string;
  thumbnail?: string;
}

interface CoursesPreviewSectionProps {
  courses: Course[];
}

export default function CoursesPreviewSection({ courses }: CoursesPreviewSectionProps) {
  const gridClass =
    courses.length === 1
      ? "grid-cols-1 max-w-md mx-auto"
      : courses.length === 2
        ? "grid-cols-1 md:grid-cols-2 max-w-3xl mx-auto"
        : "grid-cols-1 md:grid-cols-2 lg:grid-cols-3";

  return (
    <section className="py-24 relative">
      <div className="section-divider mb-24" />
      <div className="max-w-7xl mx-auto px-6 lg:px-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16">
          <div>
            <p className="text-sm text-indigo-500 font-medium mb-2">COURSES</p>
            <h2 className="text-3xl md:text-4xl font-bold mb-4 text-gray-800">
              강의는 메인 홈페이지에서 보이되,
              <span className="block gradient-text-purple">병원 단위 솔루션과는 분리됩니다.</span>
            </h2>
            <p className="text-lg text-gray-500 leading-relaxed">브랜드 전체 경험 안에서 강의는 별도의 B2C 축으로 이어집니다.</p>
          </div>
          <div className="flex items-center gap-4 mt-6 md:mt-0">
            <div className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full bg-orange-50 border border-orange-200">
              <ClockIcon />
              <span className="text-xs text-orange-700 font-medium">선착순 마감</span>
            </div>
            <Link href="/courses" className="btn-secondary">
              전체 강의 보기
            </Link>
          </div>
        </div>

        {courses.length > 0 ? (
          <div className={`grid gap-8 ${gridClass}`}>
            {courses.map((course) => (
              <CourseCard key={course.id} course={course} />
            ))}
          </div>
        ) : (
          <div className="card-premium glow-box text-center py-20">
            <p className="text-gray-500 text-lg">준비 중인 강의가 곧 공개됩니다.</p>
            <Link href="/courses" className="inline-block mt-4 text-indigo-500 font-medium hover:text-indigo-600 transition-colors">
              강의 페이지 방문하기 &rarr;
            </Link>
          </div>
        )}
      </div>
    </section>
  );
}
