import { createServerClient } from "@supabase/ssr";
import { createClient as createSupabaseClient } from "@supabase/supabase-js";
import { cookies } from "next/headers";
import { NextResponse } from "next/server";
import type { User } from "@supabase/supabase-js";

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
const supabaseServiceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

export async function createClient() {
  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error("Supabase 환경변수가 설정되지 않았습니다.");
  }

  const cookieStore = await cookies();

  // 프로덕션에서 .denjoy.info 도메인 공유 → inventory.denjoy.info 자동 SSO
  const cookieDomain =
    process.env.NODE_ENV === "production" ? ".denjoy.info" : undefined;

  return createServerClient(supabaseUrl, supabaseAnonKey, {
    cookies: {
      getAll() {
        return cookieStore.getAll();
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) => {
            cookieStore.set(name, value, {
              ...options,
              ...(cookieDomain ? { domain: cookieDomain } : {}),
            });
          });
        } catch {
          // Server Component에서 호출 시 무시
        }
      },
    },
  });
}

export async function requireUser(): Promise<
  { user: User; error: null } | { user: null; error: NextResponse }
> {
  try {
    const supabase = await createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return {
        user: null,
        error: NextResponse.json(
          { error: "인증이 필요합니다. 로그인 후 다시 시도해주세요." },
          { status: 401 }
        ),
      };
    }

    return { user, error: null };
  } catch {
    return {
      user: null,
      error: NextResponse.json(
        { error: "인증 처리 중 오류가 발생했습니다." },
        { status: 500 }
      ),
    };
  }
}

export async function requireAdmin(): Promise<
  { user: User; error: null } | { user: null; error: NextResponse }
> {
  try {
    const supabase = await createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return {
        user: null,
        error: NextResponse.json(
          { error: "인증이 필요합니다. 로그인 후 다시 시도해주세요." },
          { status: 401 }
        ),
      };
    }

    if (user.app_metadata?.role !== "admin" && user.user_metadata?.role !== "admin") {
      return {
        user: null,
        error: NextResponse.json(
          { error: "관리자 권한이 필요합니다." },
          { status: 403 }
        ),
      };
    }

    return { user, error: null };
  } catch {
    return {
      user: null,
      error: NextResponse.json(
        { error: "인증 처리 중 오류가 발생했습니다." },
        { status: 500 }
      ),
    };
  }
}

export function createAdminClient() {
  if (!supabaseUrl || !supabaseServiceRoleKey) {
    throw new Error("Supabase Admin 환경변수가 설정되지 않았습니다.");
  }
  return createSupabaseClient(supabaseUrl, supabaseServiceRoleKey);
}
