import Link from "next/link";
import Image from "next/image";
import { levelEmoji, statusColor } from "@/lib/course-constants";
import { formatPrice } from "@/lib/utils";

interface CourseCardProps {
    id: string;
    title: string;
    description: string;
    price: number;
    duration: string;
    level: string;
    category: string;
    status: string;
    slug: string;
    thumbnail?: string;
}

export default function CourseCard({ course }: { course: CourseCardProps }) {
    return (
        <Link href={`/courses/${course.slug}`}>
            <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden h-full cursor-pointer group hover:border-indigo-200 hover:shadow-lg hover:shadow-indigo-100/50 hover:-translate-y-1 transition-all duration-300">
                {course.thumbnail ? (
                    <div className="relative h-44">
                        <Image
                            src={course.thumbnail}
                            alt={course.title}
                            fill
                            className="object-cover group-hover:scale-105 transition-transform duration-300"
                        />
                    </div>
                ) : (
                    <div className="text-4xl text-center py-6 bg-slate-50 border-b border-slate-100 group-hover:bg-indigo-50/50 transition-colors duration-300">
                        {levelEmoji[course.level] || '📚'}
                    </div>
                )}

                <div className="p-5">
                    <div className="flex flex-wrap items-center gap-2 mb-3">
                        {course.status && (
                            <span className={`px-2.5 py-0.5 rounded-full text-xs font-semibold ${statusColor[course.status] || 'bg-gray-100 text-gray-500 border border-gray-200'}`}>
                                {course.status}
                            </span>
                        )}
                        {course.category && (
                            <span className="text-xs text-slate-400 font-medium">{course.category}</span>
                        )}
                    </div>

                    <h3 className="text-base font-bold text-slate-800 mb-1">{course.title}</h3>
                    <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-3">
                        {course.level} LEVEL
                    </p>

                    <p className="text-gray-500 mb-4 text-sm leading-relaxed line-clamp-2">{course.description}</p>

                    <div className="flex justify-between items-center pt-4 border-t border-slate-100">
                        <span className="text-indigo-600 font-bold text-base">
                            {course.price > 0 ? `${formatPrice(course.price)}원` : "무료"}
                        </span>
                        <span className="text-slate-400 text-xs">{course.duration}</span>
                    </div>

                    <div className="mt-3 flex items-center gap-1.5 text-sm text-indigo-500 font-medium group-hover:text-indigo-600 transition-colors duration-200">
                        <span>자세히 보기</span>
                        <svg aria-hidden="true" className="w-4 h-4 group-hover:translate-x-1 transition-transform duration-200" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                        </svg>
                    </div>
                </div>
            </div>
        </Link>
    );
}
