import { createAdminClient } from './supabase-server';

// ─── 공통 타입 ────────────────────────────────────────────────
export interface CourseRow {
  id: string;
  title: string;
  description: string | null;
  price: number;
  duration: string | null;
  level: string;
  category: string | null;
  format: string | null;
  status: string;
  is_public: boolean;
  thumbnail_url: string | null;
  slug: string | null;
  location: string | null;
  apply_link: string | null;
  max_capacity: number;
  tags: string[];
  content: unknown;
  created_at: string;
  updated_at: string;
}

export interface SessionRow {
  id: string;
  course_id: string;
  title: string;
  start_date: string | null;
  end_date: string | null;
  additional_dates: { start: string; end: string }[];
  location: string | null;
  max_capacity: number;
  current_capacity: number;
  apply_link: string | null;
  status: string;
  is_public: boolean;
  created_at: string;
  updated_at: string;
}

// ─── 강의 목록 (공개) ─────────────────────────────────────────
export async function getCourses() {
  const supabase = createAdminClient();
  const { data, error } = await supabase
    .from('courses')
    .select('id, title, description, price, duration, level, category, status, is_public, thumbnail_url, slug, tags')
    .eq('is_public', true)
    .order('created_at', { ascending: false });

  if (error) {
    console.error('강의 목록 조회 실패:', error);
    return [];
  }

  return (data ?? []).map((row: Partial<CourseRow>) => ({
    id: row.id!,
    title: row.title || '제목 없음',
    description: row.description || '',
    price: row.price || 0,
    duration: row.duration || '',
    level: row.level || '입문',
    category: row.category || '',
    status: row.status || '',
    thumbnail: row.thumbnail_url || '',
    slug: row.slug || row.id!,
    tags: row.tags || [],
  }));
}

// ─── 슬러그로 강의 조회 ───────────────────────────────────────
export async function getCourseBySlug(slug: string): Promise<{ id: string; title: string; status: string } | null> {
  const supabase = createAdminClient();
  const { data, error } = await supabase
    .from('courses')
    .select('id, title, status')
    .eq('slug', slug)
    .single();

  if (error || !data) return null;
  return { id: data.id, title: data.title, status: data.status };
}

// ─── 강의 상세 (UUID 또는 slug로 조회) ───────────────────────
export async function getCourse(idOrSlug: string) {
  const supabase = createAdminClient();
  // UUID 형식이면 id로, 아니면 slug로 조회
  const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(idOrSlug);
  const { data, error } = await supabase
    .from('courses')
    .select('*')
    .eq(isUuid ? 'id' : 'slug', idOrSlug)
    .single();

  if (error || !data) return null;
  if (!data.is_public) return null;

  return {
    id: data.id,
    title: data.title,
    description: data.description || '',
    price: data.price || 0,
    duration: data.duration || '',
    level: data.level || '입문',
    category: data.category || '',
    format: data.format || '',
    status: data.status || '',
    thumbnail: data.thumbnail_url || '',
    location: data.location || '',
    applyLink: data.apply_link || '',
    maxCapacity: data.max_capacity || 0,
    tags: data.tags || [],
    content: data.content || [],
  };
}

// ─── 회차 목록 ────────────────────────────────────────────────
export async function getSessionsByCourse(courseId: string) {
  const supabase = createAdminClient();
  const { data, error } = await supabase
    .from('sessions')
    .select('*')
    .eq('course_id', courseId)
    .eq('is_public', true)
    .order('start_date', { ascending: true });

  if (error) {
    console.error('회차 조회 실패:', error);
    return [];
  }

  return (data ?? []).map((row: SessionRow) => {
    const dates: { start: string; end: string }[] = Array.isArray(row.additional_dates)
      ? row.additional_dates
      : [];
    if (dates.length === 0 && row.start_date) {
      dates.push({ start: row.start_date, end: row.end_date || row.start_date });
    }
    return {
      id: row.id,
      title: row.title,
      courseDate: row.start_date || '',
      courseDateEnd: row.end_date || '',
      dates,
      location: row.location || '',
      maxCapacity: row.max_capacity,
      currentCapacity: row.current_capacity,
      applyLink: row.apply_link || '',
      status: row.status,
      isPublic: row.is_public,
    };
  });
}

// ─── 후기 ─────────────────────────────────────────────────────
export async function getReviewsByCourse(courseId: string) {
  const supabase = createAdminClient();
  const { data, error } = await supabase
    .from('reviews')
    .select('*')
    .eq('course_id', courseId)
    .order('created_at', { ascending: false });

  if (error) return [];

  return (data ?? []).map((row) => ({
    id: row.id,
    title: row.title,
    authorName: row.author_name || '',
    rating: row.rating || 0,
    content: row.content || '',
    date: row.written_date || '',
  }));
}

// ─── 질문 ─────────────────────────────────────────────────────
