// ─── 이메일로 신청 내역 조회 ──────────────────────────────────
export async function getRegistrationsByEmail(email: string) {
  const supabase = createAdminClient();
  const { data, error } = await supabase
    .from('registrations')
    .select('*')
    .eq('email', email)
    .order('applied_at', { ascending: false });

  if (error) return [];

  return (data ?? []).map((row) => ({
    id: row.id,
    name: row.name,
    email: row.email,
    courseName: row.course_name,
    price: String(row.course_price || 0),
    status: row.status || '신청완료',
    phone: row.phone || '',
    appliedAt: row.applied_at || row.created_at,
    paymentStatus: row.payment_status || '',
  }));
}

// ─── 강의명으로 신청 인원 수 조회 ────────────────────────────
export async function getRegistrationCountByCourseName(courseName: string): Promise<number> {
  if (!courseName) return 0;

  const supabase = createAdminClient();
  const { count, error } = await supabase
    .from('registrations')
    .select('*', { count: 'exact', head: true })
    .eq('course_name', courseName)
    .neq('status', '취소');

  if (error) return 0;
  return count ?? 0;
}
